INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES
(gen_random_uuid(), 'ez', 10, 1, NULL, 'João Calvino em Ez 10:1', 'Na leitura de João Calvino, vemos a centralidade das Escrituras e da graça soberana. Ezequiel 10 evidencia juízo, esperança e promessa messiânica como eixo da vida do povo de Deus, com ênfase em esperança escatológica. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'João Calvino', 'commentary', '#800080', NOW()),
(gen_random_uuid(), 'ez', 11, 1, NULL, 'John Brown of Haddington em Ez 11:1', 'Segundo John Brown of Haddington, a piedade prática e a santificação do coração ilumina o sentido deste texto. Ezequiel 11 mostra que juízo, esperança e promessa messiânica sustenta a caminhada da fé, especialmente em obediência da fé. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'John Brown of Haddington', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'ez', 12, 1, NULL, 'Albert Barnes em Ez 12:1', 'Na leitura de Albert Barnes, vemos a exposição textual com aplicação pastoral objetiva. Ezequiel 12 evidencia juízo, esperança e promessa messiânica como eixo da vida do povo de Deus, com ênfase em adoração reverente. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Albert Barnes', 'commentary', '#B45309', NOW()),
(gen_random_uuid(), 'ez', 13, 1, NULL, 'Martinho Lutero em Ez 13:1', 'Martinho Lutero interpreta este versículo a partir de a centralidade das Escrituras e da graça soberana. Em Ezequiel 13, Deus revela juízo, esperança e promessa messiânica de forma pastoral e transformadora, promovendo perseverança na tribulação. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Martinho Lutero', 'commentary', '#800080', NOW()),
(gen_random_uuid(), 'ez', 14, 1, NULL, 'Thomas Boston em Ez 14:1', 'Thomas Boston destaca a piedade prática e a santificação do coração. Em Ezequiel 14, o foco recai sobre juízo, esperança e promessa messiânica e chama a igreja para fidelidade na aliança. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Thomas Boston', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'ez', 15, 1, NULL, 'Herman Bavinck em Ez 15:1', 'Herman Bavinck interpreta este versículo a partir de a coerência doutrinária aplicada à vida cristã. Em Ezequiel 15, Deus revela juízo, esperança e promessa messiânica de forma pastoral e transformadora, promovendo vida de oração. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Herman Bavinck', 'commentary', '#1D4ED8', NOW()),
